import { Button } from "@chakra-ui/react";
import React from "react";
import { AiFillLinkedin, AiOutlineGithub } from "react-icons/ai";
import styles from "./HeroSection.module.css";
const HeroSection = () => {
  return (
    <div className={styles.rootCont}>
      <div className={styles.nameCont}>
        <p>Hi,</p>
        <p>
          I am <span>Akash Gupta</span>
        </p>
        <p>Full Stack Web Developer</p>
        <a href="https://drive.google.com/file/d/1mJkvzRTR0s2VGp4SibAP6Hb569wZ_zvn/view?usp=share_link" target="_blank" download>
          <Button colorScheme="blue"> Resume
          </Button>
        </a>
      </div>
   <div className={styles.photoCont}>
        <img src="https://avatars.githubusercontent.com/u/101566767?v=4" alt="akashimg" className={styles.heroImg} />
      </div>
      <div className={styles.socialCont}>
        <a
          rel="noreferrer"
          href="https://www.linkedin.com/in/akash-g928/"
          target="_blank"
          className={styles.linkdin}
        >
          <AiFillLinkedin size={40} />
        </a>
        <a
          rel="noreferrer"
          href="https://github.com/Aakash928"
          target="_blank"
          className={styles.github}
        >
          <AiOutlineGithub size={40} />
        </a>
      </div>
    </div>
  );
};
export default HeroSection;